class Solution(object):
    def numFactoredBinaryTrees(self, arr):
        MOD = 10**9 + 7
        arr.sort()
        dp = {num: 1 for num in arr}
        arr_set = set(arr)
        for num in arr:
            for i in range(len(arr)):
                if arr[i] >= num:
                    break
                if num % arr[i] == 0:
                    other = num // arr[i]
                    if other in arr_set:
                        dp[num] = (dp[num] + dp[arr[i]] * dp[other]) % MOD
        return sum(dp.values()) % MOD
